import{_ as i,o as d,c as e,a2 as s}from"./chunks/framework.N6Nd-M9-.js";const x=JSON.parse('{"title":"职业规划","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/Meeting/职业规划.md","filePath":"notes/培训/Meeting/职业规划.md"}'),o={name:"notes/培训/Meeting/职业规划.md"};function r(a,t,l,n,c,b){return d(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="职业规划" tabindex="-1">职业规划 <a class="header-anchor" href="#职业规划" aria-label="Permalink to &quot;职业规划&quot;">​</a></h1><blockquote><p>关于规划、价值、成长与心态的深度思考</p></blockquote><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;margin:20px 0;"><div class="tc-blue tc-bold tc-center" style="font-size:20px;margin-bottom:20px;">📑 内容导航</div><div style="display:flex;flex-wrap:wrap;gap:12px;justify-content:center;"><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">🗺️</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">关于规划</div><div class="tc-muted tc-sm">学业规划<br>职业起点</div></div><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">💎</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">价值与能力</div><div class="tc-muted tc-sm">价值交换<br>核心公式</div></div><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">🚀</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">工作与成长</div><div class="tc-muted tc-sm">能力锻炼<br>发展定义</div></div><div class="tc-center" style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;"><div style="font-size:32px;margin-bottom:8px;">🧠</div><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:8px;">心态与成熟</div><div class="tc-muted tc-sm">勇于尝试<br>接受不完美</div></div></div></div><hr><hr><h2 id="🗺️-一、关于规划" tabindex="-1">🗺️ 一、关于规划 <a class="header-anchor" href="#🗺️-一、关于规划" aria-label="Permalink to &quot;🗺️ 一、关于规划&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">🎓 学业规划</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 多数人只规划到大学，很少规划到研究生。这是因为上大学不是我们自己的想法和规划，而是身边人的絮叨，且大学期间的经历充满不确定性（&quot;上大学就磕磕绊绊&quot;）。 </div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-orange tc-bold" style="font-size:16px;margin-bottom:12px;">⚠️ 缺乏规划的原因</div><div class="tc-body" style="font-size:14px;line-height:1.8;"><strong>1. 早期规划多由父母安排</strong>，个人缺乏自主性。 <br><br><strong>2. 对自身目标不清晰</strong>。例如，面试时可以说出过去的成绩，但当被问及未来规划时，却回答&quot;不知道&quot;，只是想找份工作安稳度日。 <br><br><strong>3. 人生变数太多</strong>，长期规划困难（&quot;几十年中可能产生很多意外&quot;）。 </div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">🚩 职业起点</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 许多人的第一份工作选择是<strong>&quot;误打误撞&quot;</strong>的，大多核心诉求是&quot;离家近&quot;、&quot;感觉不错&quot;，并没有长远的职业规划。 </div></div><hr><h2 id="💎-二、关于价值与能力" tabindex="-1">💎 二、关于价值与能力 <a class="header-anchor" href="#💎-二、关于价值与能力" aria-label="Permalink to &quot;💎 二、关于价值与能力&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">⚖️ 价值的本质</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 社会运行的本质是<strong>价值交换</strong>。个人价值取决于做事产生的成果。 </div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">💪 能力界定</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 能力是能够<strong>稳定地产出良好成果</strong>的本事。例如，能独立、完整地解决客户问题，就是一种能力。 </div></div><div class="tc-center" style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-green tc-bold" style="font-size:16px;margin-bottom:12px;">🔑 核心公式</div><div class="tc-body" style="font-size:14px;line-height:1.8;"><strong>想成为什么样的人 = 需要具备对应的能力 + 通过工作实践训练出来</strong></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-red tc-bold" style="font-size:16px;margin-bottom:12px;">⚠️ 关系与实力</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 依赖&quot;关系&quot;获得的工作可能不稳固（&quot;关系已经不管用了&quot;）。长久来看，最终依靠的是个人的<strong>实力和能力</strong>。 </div></div><hr><h2 id="📈-三、关于工作与成长" tabindex="-1">📈 三、关于工作与成长 <a class="header-anchor" href="#📈-三、关于工作与成长" aria-label="Permalink to &quot;📈 三、关于工作与成长&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">🎯 工作的意义</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 在获得财务自由前，工作是不可或缺的。对年轻人而言，工作的首要目的不应该是当下赚多少钱（&quot;只能赚辛苦钱，叫生存&quot;），而是<strong class="tc-blue">获取和锻炼能力</strong>，为未来（三年、五年后）创造价值。 </div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-blue tc-bold" style="font-size:16px;margin-bottom:12px;">📈 发展的定义</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 发展不等于工龄增长或团队人数增加。发展的关键是<strong>个人有进步、有成长、有能力上的改变和提升</strong>。 </div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-green tc-bold" style="font-size:16px;margin-bottom:12px;">🛠️ 如何获得发展</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 把当前的事情做好，做出成果。例如，作为组长，把人带好、培训好，自然能获得晋升机会（&quot;今天把事情做好了，你不用管你当下没有得到，你肯定会（被）记得&quot;）。 </div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:20px;margin:16px 0;"><div class="tc-orange tc-bold" style="font-size:16px;margin-bottom:12px;">⏰ 年轻是资本</div><div class="tc-body" style="font-size:14px;line-height:1.8;"> 20岁出头的年纪，精力充沛、学习能力强，是训练能力、接受挑战的黄金时期，不应计较短期得失或与旁人比较&quot;轻松与否&quot;。 </div></div><hr><h2 id="🧘-四、关于心态与成熟" tabindex="-1">🧘 四、关于心态与成熟 <a class="header-anchor" href="#🧘-四、关于心态与成熟" aria-label="Permalink to &quot;🧘 四、关于心态与成熟&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:16px 0;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">🔥</div><div class="tc-blue tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">勇于尝试，不怕犯错</div><div class="tc-body tc-sm" style="line-height:1.6;"> 能力的获取途径只有训练，要不怕做错，在挫折中总结经验（&quot;跌倒又不可怕&quot;）。 </div></div><div style="flex:1;min-width:200px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">🌟</div><div class="tc-green tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">接受不完美</div><div class="tc-body tc-sm" style="line-height:1.6;"> 成熟就是知道事情不完美，但不影响你接受它。这包括接受不完美的父母、同事和公司，并给予尊重。 </div></div><div style="flex:1;min-width:200px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">🧠</div><div class="tc-orange tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">区分事实与观点</div><div class="tc-body tc-sm" style="line-height:1.6;"> 要能自己判断是非，对于已成事实的事情，无需过分在意他人的观点和建议。 </div></div><div style="flex:1;min-width:200px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:20px;"><div class="tc-center" style="font-size:28px;margin-bottom:8px;">🤐</div><div class="tc-red tc-bold tc-center" style="font-size:16px;margin-bottom:8px;">保持城府，专注自身</div><div class="tc-body tc-sm" style="line-height:1.6;"> 不要私下诋毁或随意评价他人，专注做好自己的事，在过程中获得成长。即使现阶段收益有限，有意义的成长经历也胜过无意义的&quot;贫穷&quot;。 </div></div></div>',24)])])}const g=i(o,[["render",r]]);export{x as __pageData,g as default};
